.mrg-grid {
  --mrg-grid-gap: var(--mrg-semantic-space-stack-md);
  --mrg-grid-minimum: 16rem;
  align-items: stretch;
  display: grid;
  gap: var(--mrg-grid-gap);
  grid-template-columns: repeat(auto-fit, minmax(min(100%, var(--mrg-grid-minimum)), 1fr));
  min-inline-size: 0;
}

.mrg-grid > * {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-grid[data-minimum="compact"] {
  --mrg-grid-minimum: 12rem;
}

.mrg-grid[data-minimum="wide"] {
  --mrg-grid-minimum: 20rem;
}

.mrg-grid[data-gap="none"] {
  --mrg-grid-gap: 0px;
}

.mrg-grid[data-gap="sm"] {
  --mrg-grid-gap: var(--mrg-semantic-space-stack-sm);
}

.mrg-grid[data-gap="lg"] {
  --mrg-grid-gap: var(--mrg-semantic-space-stack-lg);
}

.mrg-grid[data-columns="1"] {
  grid-template-columns: minmax(0, 1fr);
}

.mrg-grid[data-columns="2"] {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.mrg-grid[data-columns="3"] {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.mrg-grid[data-columns="4"] {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.mrg-grid[data-columns="5"] {
  grid-template-columns: repeat(5, minmax(0, 1fr));
}

.mrg-grid[data-columns="6"] {
  grid-template-columns: repeat(6, minmax(0, 1fr));
}

.mrg-grid[data-align="start"] {
  align-items: start;
}

.mrg-grid[data-align="center"] {
  align-items: center;
}

.mrg-grid[data-align="end"] {
  align-items: end;
}

.mrg-grid[data-equal-rows="true"] {
  grid-auto-rows: 1fr;
}

.mrg-grid:is(ul, ol) {
  margin-block: 0;
  padding-inline-start: var(--mrg-semantic-space-stack-lg);
}

.mrg-grid:is(ul, ol)[data-list-style="none"] {
  list-style: none;
  padding-inline-start: 0;
}

import { createElement, forwardRef, type HTMLAttributes } from "react";

import "./grid.css";

export type GridColumns = "auto" | 1 | 2 | 3 | 4 | 5 | 6;
export type GridMinimum = "compact" | "default" | "wide";
export type GridGap = "none" | "sm" | "md" | "lg";
export type GridAlign = "stretch" | "start" | "center" | "end";
export type GridElement = "div" | "section" | "ul" | "ol";
export type GridListStyle = "preserve" | "none";

export interface GridProps extends HTMLAttributes<HTMLElement> {
  /** Uses a fixed column count or an auto-fit grid that responds to the available width. */
  readonly columns?: GridColumns;
  /** Selects the semantic minimum track width used by the auto-fit layout. */
  readonly minimum?: GridMinimum;
  /** Sets tokenized row and column space without accepting arbitrary CSS lengths. */
  readonly gap?: GridGap;
  /** Aligns grid items within their block-axis tracks. */
  readonly align?: GridAlign;
  /** Chooses a restricted semantic root element instead of unrestricted polymorphism. */
  readonly element?: GridElement;
  /** Preserves native list markers by default or removes them for application-style grids. */
  readonly listStyle?: GridListStyle;
  /** Equalizes intrinsic row tracks; false keeps content-sized rows. */
  readonly equalRows?: boolean;
}

function joinGridClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-grid"
    : `mrg-grid ${className}`;
}

export const Grid = forwardRef<HTMLElement, GridProps>(function Grid(
  {
    align = "stretch",
    className,
    columns = "auto",
    element = "div",
    equalRows = false,
    gap = "md",
    listStyle = "preserve",
    minimum = "default",
    ...nativeProps
  },
  forwardedRef,
) {
  return createElement(element, {
    ...nativeProps,
    ref: forwardedRef,
    className: joinGridClassName(className),
    "data-align": align,
    "data-columns": columns,
    "data-element": element,
    "data-equal-rows": equalRows ? "true" : undefined,
    "data-gap": gap,
    "data-list-style": listStyle,
    "data-minimum": minimum,
    "data-slot": "grid",
  });
});

Grid.displayName = "Grid";

export { Grid } from "./grid";
export type {
  GridAlign,
  GridColumns,
  GridElement,
  GridGap,
  GridListStyle,
  GridMinimum,
  GridProps,
} from "./grid";
